                      CREATE view [SSRS].[JuniorLeague_SeasonCurrLast]     as    Select * FROM   (  SELECT Case [League_ID] When 8205 then 15363 Else League_ID END League_ID        ,Case [League_ID] When 15363 then 'Northumberland and Tyneside Senior Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]    FROM [SSRS].[JuniorLeagues_SeasonTD_2022]    UNION      Select Case [League_ID] When 8205 then 15363 Else League_ID END        ,Case [League_ID] When 8205 then 'Northumberland and Tyneside Senior Cricket League' Else REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') END AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]  FROM .[SSRS].[JuniorLeagues_SeasonTD_2021]     )A     WHere MonthofFixture =  DATEPART(month,getdate())-1                